
/*
 * FrontWars Macro Hack by KebabLord
 * Automatically generated at 8/6/2026
 */
function showToast(message) {
  const DURATION = 2000;
  const containerId = '__toast_container_bl';

  let c = document.getElementById(containerId);
  if (!c) {
    c = document.createElement('div');
    c.id = containerId;
    Object.assign(c.style, {
      position: 'fixed',
      left: '32px',
      bottom: '32px',
      display: 'flex',
      flexDirection: 'column-reverse',
      gap: '16px',
      maxWidth: '40vw',
      zIndex: '2147483647',
      pointerEvents: 'none'
    });
    (document.body || document.documentElement).appendChild(c);
  }

  const t = document.createElement('div');
  t.textContent = String(message);
  Object.assign(t.style, {
    background: '#111111',
    color: '#ffffff',
    fontFamily: 'system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif',
    fontSize: '28px',
    lineHeight: '1.2',
    padding: '20px 24px',
    borderRadius: '16px',
    boxShadow: '0 12px 36px rgba(0,0,0,.35)',
    pointerEvents: 'none',
    opacity: '0',
    transform: 'translateY(16px)',
    transition: 'opacity 180ms ease-out, transform 180ms ease-out',
    whiteSpace: 'pre-wrap',
    wordBreak: 'break-word',
    overflowWrap: 'anywhere'
  });

  c.appendChild(t);

  requestAnimationFrame(() => {
    t.style.opacity = '1';
    t.style.transform = 'translateY(0)';
  });

  setTimeout(() => {
    t.style.opacity = '0';
    t.style.transform = 'translateY(16px)';
  }, DURATION - 180);

  setTimeout(() => {
    if (t.parentNode) t.parentNode.removeChild(t);
    if (c.children.length === 0) c.remove();
  }, DURATION);
}


(function initSpamLoopWithUI() {
    const box = document.createElement("div");
    box.textContent = "SPAMMING ACTIVE";
    box.style.position = "fixed";
    box.style.top = "12px";
    box.style.left = "50%";
    box.style.transform = "translateX(-50%)";
    box.style.padding = "8px 16px";
    box.style.fontFamily = "Arial, sans-serif";
    box.style.fontSize = "14px";
    box.style.fontWeight = "bold";
    box.style.color = "#111";
    box.style.background = "orange";
    box.style.border = "3px solid #cc8400";
    box.style.borderRadius = "0";
    box.style.zIndex = "999999";
    box.style.display = "none";
    box.style.pointerEvents = "none";

    document.body.appendChild(box);

    let last = 0;
    const interval = 10;

    let lastKeepghost;
    let lastSpam;
    showToast("Macro hack is loaded.")

    const loop = (t) => {
        if (t - last >= interval) {
            last = t;

            if (window.keepghost && window.spam) {
                try {
                    window.executePlacement(window.obj_placement?._cursorLoc);
                } catch (err) {
                    console.log("7331 ERR:", err);
                }
            }
        }

        if (window.keepghost !== lastKeepghost || window.spam !== lastSpam) {
            lastKeepghost = window.keepghost;
            lastSpam = window.spam;

            if (window.keepghost === true) {
                box.style.display = "block";

                if (window.spam === true) {
                    box.style.background = "red";
                    box.style.borderColor = "#b30000";
                } else {
                    box.style.background = "orange";
                    box.style.borderColor = "#cc8400";
                }
            } else {
                box.style.display = "none";
            }
        }

        requestAnimationFrame(loop);
    };

    requestAnimationFrame(loop);
})();
